import {
    IMessageDataWrapper,
    IMessageParser,
} from '@nitrots/nitro-renderer/src/core';

export interface ZeusStatsData {
    health: number;
    maxHealth: number;
}

export class ZeusStatsParser implements IMessageParser {
    private _stats: ZeusStatsData = {
        health: 0,
        maxHealth: 250,
    };

    public flush(): boolean {
        this._stats = {
            health: 0,
            maxHealth: 250,
        };
        return true;
    }

    public parse(wrapper: IMessageDataWrapper): boolean {
        this._stats.health = wrapper.readInt();
        this._stats.maxHealth = wrapper.readInt();

        const event = new CustomEvent('zeus_stats_update', {
            detail: this._stats,
        });
        window.dispatchEvent(event);

        return true;
    }

    public get stats(): ZeusStatsData {
        return this._stats;
    }
}
